  it("should sum numbers correctly", () => {
    expect(sum([1, 2, 3])).toBe(6);
  });

  it("should return 0 for empty array", () => {
    expect(sum([])).toBe(0);
  });
});
```

## The Bug - Source Code Analysis

**File: src/utils.ts** (lines 1-11)

The off-by-one bug is visible in the `processItems` function at line 7:

```typescript
export function processItems(items: string[]): string[] {
  const results: string[] = [];
  for (let i = 0; i < items.length - 1; i++) {  // BUG: Should be i < items.length
    results.push(items[i].toUpperCase());
  }
  return results;
}
```

The loop condition `i < items.length - 1` stops before the last item, preventing it from being processed.

